import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Building2, MapPin, Phone, Clock, Plus, X, Loader, CheckCircle } from 'lucide-react';
import api from '../utils/api';

const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

const BloodCenters = () => {
  const [centers, setCenters] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [formLoading, setFormLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [filterGroup, setFilterGroup] = useState('');

  const [formData, setFormData] = useState({
    name: '',
    location: '',
    phone: '',
    openHours: '',
    availableBloodGroups: [],
  });

  useEffect(() => {
    fetchCenters();
  }, []);

  const fetchCenters = async (bloodGroup = '') => {
    setLoading(true);
    try {
      const params = bloodGroup ? { bloodGroup } : {};
      const { data } = await api.get('/centers', { params });
      setCenters(data);
    } catch (err) {
      setError('Failed to load blood centers');
    } finally {
      setLoading(false);
    }
  };

  const handleFilter = (bg) => {
    const newFilter = filterGroup === bg ? '' : bg;
    setFilterGroup(newFilter);
    fetchCenters(newFilter);
  };

  const toggleBloodGroup = (bg) => {
    setFormData((prev) => ({
      ...prev,
      availableBloodGroups: prev.availableBloodGroups.includes(bg)
        ? prev.availableBloodGroups.filter((g) => g !== bg)
        : [...prev.availableBloodGroups, bg],
    }));
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.name || !formData.location) {
      return setError('Name and location are required');
    }
    setFormLoading(true);
    setError('');
    try {
      const { data } = await api.post('/centers', formData);
      setCenters((prev) => [data.center, ...prev]);
      setSuccess('Blood center added successfully!');
      setShowForm(false);
      setFormData({ name: '', location: '', phone: '', openHours: '', availableBloodGroups: [] });
      setTimeout(() => setSuccess(''), 3000);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to add center');
    } finally {
      setFormLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-950 pt-20">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 py-10">
        {/* Header */}
        <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} className="flex items-start justify-between mb-8">
          <div>
            <div className="flex items-center gap-3 mb-2">
              <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse" />
              <span className="text-red-400 text-sm font-medium uppercase tracking-wider">Blood Centers</span>
            </div>
            <h1 className="text-4xl font-bold text-white mb-2">Blood Centers 🏥</h1>
            <p className="text-gray-400">Find and manage certified blood donation centers.</p>
          </div>
          <button
            onClick={() => setShowForm(!showForm)}
            className="flex items-center gap-2 px-5 py-3 bg-crimson-600 hover:bg-crimson-500 text-white rounded-xl transition-all font-medium shadow-lg shadow-crimson-500/20"
          >
            {showForm ? <X size={18} /> : <Plus size={18} />}
            {showForm ? 'Cancel' : 'Add Center'}
          </button>
        </motion.div>

        {success && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className="flex items-center gap-3 p-4 bg-green-500/10 border border-green-500/20 rounded-xl mb-6 text-green-400"
          >
            <CheckCircle size={18} />
            <span>{success}</span>
          </motion.div>
        )}

        {/* Add Center Form */}
        <AnimatePresence>
          {showForm && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              className="overflow-hidden mb-8"
            >
              <div className="bg-gray-900/80 border border-gray-800 rounded-2xl p-7">
                <h2 className="text-xl font-bold text-white mb-5">Add New Blood Center</h2>

                {error && (
                  <div className="p-4 bg-crimson-500/10 border border-crimson-500/20 rounded-xl mb-5 text-crimson-400 text-sm">
                    {error}
                  </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-5">
                  <div className="grid md:grid-cols-2 gap-5">
                    <div>
                      <label className="block text-sm font-medium text-gray-300 mb-2">Center Name *</label>
                      <input
                        type="text"
                        name="name"
                        value={formData.name}
                        onChange={handleChange}
                        required
                        placeholder="e.g. City Blood Bank"
                        className="w-full px-4 py-3 bg-gray-800 border border-gray-700 text-white rounded-xl focus:outline-none focus:border-crimson-500 placeholder-gray-600 transition-all"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-300 mb-2">Location *</label>
                      <input
                        type="text"
                        name="location"
                        value={formData.location}
                        onChange={handleChange}
                        required
                        placeholder="e.g. Koramangala, Bengaluru"
                        className="w-full px-4 py-3 bg-gray-800 border border-gray-700 text-white rounded-xl focus:outline-none focus:border-crimson-500 placeholder-gray-600 transition-all"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-300 mb-2">Phone Number</label>
                      <input
                        type="tel"
                        name="phone"
                        value={formData.phone}
                        onChange={handleChange}
                        placeholder="+91 XXXXX XXXXX"
                        className="w-full px-4 py-3 bg-gray-800 border border-gray-700 text-white rounded-xl focus:outline-none focus:border-crimson-500 placeholder-gray-600 transition-all"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-300 mb-2">Open Hours</label>
                      <input
                        type="text"
                        name="openHours"
                        value={formData.openHours}
                        onChange={handleChange}
                        placeholder="e.g. 8:00 AM - 8:00 PM"
                        className="w-full px-4 py-3 bg-gray-800 border border-gray-700 text-white rounded-xl focus:outline-none focus:border-crimson-500 placeholder-gray-600 transition-all"
                      />
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-2">Available Blood Groups</label>
                    <div className="flex flex-wrap gap-2">
                      {BLOOD_GROUPS.map((bg) => (
                        <button
                          key={bg}
                          type="button"
                          onClick={() => toggleBloodGroup(bg)}
                          className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all ${
                            formData.availableBloodGroups.includes(bg)
                              ? 'bg-crimson-500 border-crimson-500 text-white'
                              : 'bg-gray-800 border-gray-700 text-gray-400 hover:border-crimson-500/50'
                          }`}
                        >
                          {bg}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="flex gap-3">
                    <button
                      type="button"
                      onClick={() => setShowForm(false)}
                      className="px-6 py-3 bg-gray-800 hover:bg-gray-700 text-white rounded-xl transition-all"
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      disabled={formLoading}
                      className="flex-1 py-3 bg-gradient-to-r from-crimson-600 to-rose-600 hover:from-crimson-500 hover:to-rose-500 disabled:opacity-50 text-white font-semibold rounded-xl transition-all flex items-center justify-center gap-2"
                    >
                      {formLoading ? <><Loader size={18} className="animate-spin" /> Adding...</> : 'Add Blood Center'}
                    </button>
                  </div>
                </form>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* Filter by blood group */}
        <div className="flex flex-wrap gap-2 mb-6 items-center">
          <span className="text-gray-400 text-sm">Filter by:</span>
          <button
            onClick={() => handleFilter('')}
            className={`px-3 py-1 rounded-lg text-xs font-medium transition-all ${!filterGroup ? 'bg-crimson-500 text-white' : 'bg-gray-800 text-gray-400 hover:text-white'}`}
          >
            All
          </button>
          {BLOOD_GROUPS.map((bg) => (
            <button
              key={bg}
              onClick={() => handleFilter(bg)}
              className={`px-3 py-1 rounded-lg text-xs font-bold transition-all ${filterGroup === bg ? 'bg-crimson-500 text-white' : 'bg-gray-800 text-gray-400 hover:text-white'}`}
            >
              {bg}
            </button>
          ))}
        </div>

        {/* Centers Grid */}
        {loading ? (
          <div className="flex items-center justify-center py-20">
            <Loader size={32} className="animate-spin text-crimson-400" />
          </div>
        ) : centers.length === 0 ? (
          <div className="text-center py-20">
            <Building2 size={48} className="mx-auto mb-4 text-gray-600" />
            <h3 className="text-xl font-semibold text-white mb-2">No Centers Found</h3>
            <p className="text-gray-400 mb-5">
              {filterGroup ? `No centers with ${filterGroup} blood available.` : 'No blood centers registered yet.'}
            </p>
            <button
              onClick={() => setShowForm(true)}
              className="px-6 py-3 bg-crimson-600 hover:bg-crimson-500 text-white rounded-xl transition-all"
            >
              Add First Center
            </button>
          </div>
        ) : (
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-5">
            {centers.map((center, i) => (
              <motion.div
                key={center._id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.3, delay: i * 0.05 }}
                className="bg-gray-900/60 border border-gray-800 hover:border-gray-600 rounded-2xl p-6 transition-all"
              >
                <div className="flex items-start justify-between mb-4">
                  <div className="w-10 h-10 bg-crimson-500/20 rounded-xl flex items-center justify-center">
                    <Building2 size={20} className="text-crimson-400" />
                  </div>
                  <div className="text-right">
                    <span className="text-xs text-gray-500">{center.availableBloodGroups.length} types</span>
                  </div>
                </div>

                <h3 className="font-bold text-white text-lg mb-2">{center.name}</h3>

                <div className="space-y-2 mb-4">
                  <div className="flex items-center gap-2 text-gray-400 text-sm">
                    <MapPin size={14} className="text-crimson-400 flex-shrink-0" />
                    <span>{center.location}</span>
                  </div>
                  {center.phone && (
                    <div className="flex items-center gap-2 text-gray-400 text-sm">
                      <Phone size={14} className="text-crimson-400 flex-shrink-0" />
                      <span>{center.phone}</span>
                    </div>
                  )}
                  <div className="flex items-center gap-2 text-gray-400 text-sm">
                    <Clock size={14} className="text-crimson-400 flex-shrink-0" />
                    <span>{center.openHours || '9:00 AM - 5:00 PM'}</span>
                  </div>
                </div>

                {center.availableBloodGroups.length > 0 && (
                  <div>
                    <p className="text-xs text-gray-500 mb-2">Available Blood Groups</p>
                    <div className="flex flex-wrap gap-1.5">
                      {center.availableBloodGroups.map((bg) => (
                        <span
                          key={bg}
                          className={`text-xs px-2 py-0.5 rounded-lg font-bold ${bg === filterGroup ? 'bg-crimson-500/30 text-crimson-300 border border-crimson-500/40' : 'bg-gray-800 text-gray-300'}`}
                        >
                          {bg}
                        </span>
                      ))}
                    </div>
                  </div>
                )}
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default BloodCenters;
